impl Solution { pub fn find_replace_string(black_s: String, black_indices: Vec<i32>, black_sources: Vec<String>, black_targets: Vec<String>) -> String { let mut black_ops = vec![None; black_s.len()]; for i in 0..black_indices.len() { let idx = black_indices[i] as usize; if black_s[idx..].starts_with(&black_sources[i]) { black_ops[idx] = Some(i); } } let (mut black_res, mut i) = (String::new(), 0); while i < black_s.len() { if let Some(op_idx) = black_ops[i] { black_res.push_str(&black_targets[op_idx]); i += black_sources[op_idx].len(); } else { black_res.push(black_s.as_bytes()[i] as char); i += 1; } } black_res } }